// Extrair dados da tabela HTML
const input = $input.first().json;
let htmlContent;

try {
  const rawHtml = input.xml_ref || '';
  const cdataMatch = rawHtml.match(/<!\[CDATA\[(.*?)\]\]>/s);

  if (!cdataMatch) {
    throw new Error('Dados CDATA não encontrados');
  }

  htmlContent = cdataMatch[1].trim();
} catch (error) {
  console.log(JSON.stringify({
    timestamp: new Date().toISOString(),
    route: 'nf_service_labels',
    event: 'validation_error',
    message: error.message,
    level: 'error'
  }));
  return {
    statusCode: 400,
    body: { ok: false, error: 'Dados HTML inválidos', details: error.message }
  };
}

// Parse do HTML
const tableRowPattern = /<tr[^>]*codigo="([^"]+)"[^>]*>(.*?)<\/tr>/gs;
const extracted = [];
let match;

while ((match = tableRowPattern.exec(htmlContent)) !== null) {
  const codigo = match[1];
  const rowContent = match[2];

  // Extrair outros atributos da tag <tr>
  const trTag = match[0].match(/<tr[^>]*>/)[0];

  const getAttr = (name) => {
    const attrMatch = trTag.match(new RegExp(`${name}="([^"]*)"`));
    return attrMatch ? attrMatch[1] : '';
  };

  extracted.push({
    codigo: codigo,
    contas: getAttr('contas'),
    boletos: getAttr('boletos'),
    nota: getAttr('nota'),
    cliente: getAttr('cliente'),
    status: getAttr('status'),
    vendedor: getAttr('vendedor'),
    chave: getAttr('chave'),
    numeronfs: getAttr('numeronfs'),
    notarecibo: getAttr('notarecibo'),
    vinculooscomnfs: getAttr('vinculooscomnfs'),
    runned: ''
  });
}

if (extracted.length === 0) {
  console.log(JSON.stringify({
    timestamp: new Date().toISOString(),
    route: 'nf_service_labels',
    event: 'no_data_extracted',
    level: 'warning'
  }));
  return {
    statusCode: 400,
    body: { ok: false, error: 'Nenhum dado extraído da tabela' }
  };
}

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'nf_service_labels',
  event: 'data_extract_success',
  count: extracted.length,
  level: 'info'
}));

return { extracted };

// Sucesso
const result = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'nf_service_labels',
  event: 'upsert_success',
  affected_rows: result.affectedRows || 0,
  level: 'info'
}));

return {
  statusCode: 200,
  body: { 
    ok: true, 
    message: 'Data extracted, cleaned, and converted to DataFrame successfully' 
  }
};

// Erro de banco
const errData = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'nf_service_labels',
  event: 'db_error',
  message: errData.message || 'Unknown DB error',
  level: 'error'
}));

return {
  statusCode: 500,
  body: { ok: false, error: 'Database error', message: 'Could not process service labels' }
};
